// build-shopify-pages-navigation — Validate Pages/Nav Input
// Validates store_blueprint (pages + navigation) and runtime_config; extracts shop_url.
// Safety rules: no deletes, idempotent upsert by handle, new pages never auto-published.

const input = $input.first().json;

const runtimeConfig  = input.runtime_config   || {};
const storeBlueprint = input.store_blueprint   || null;
const contentStrategy = input.content_strategy || {};
// project_id is top-level; runtime_config does not carry it directly
const projectId      = input.project_id        || runtimeConfig.project_id || null;

if (!projectId) {
  throw new Error('MISSING_RUNTIME_CONFIG: build-shopify-pages-navigation requires project_id (top-level) or runtime_config.project_id');
}

if (!storeBlueprint) {
  throw new Error('MISSING_ARTIFACT: store_blueprint is required but was not found in trigger input');
}

const pages      = storeBlueprint.pages      || [];
const navigation = storeBlueprint.navigation || [];

if (pages.length === 0 && navigation.length === 0) {
  throw new Error('INVALID_BLUEPRINT: store_blueprint.pages and store_blueprint.navigation are both empty — nothing to deploy');
}

// resolve-runtime-config uses keys: shopify_shop_url, shopify_api_version
const shopUrl    = runtimeConfig.shopify_shop_url    || runtimeConfig.shop_url    || runtimeConfig.STORE_OS_SHOPIFY_SHOP_URL    || null;
const apiVersion = runtimeConfig.shopify_api_version || runtimeConfig.api_version || runtimeConfig.STORE_OS_SHOPIFY_API_VERSION || '2026-01';

if (!shopUrl) {
  throw new Error(
    'MISSING_CONFIG: shop_url not found in runtime_config. ' +
    'Ensure STORE_OS_SHOPIFY_SHOP_URL is set in env or passed as smoke_test_config.STORE_OS_SHOPIFY_SHOP_URL'
  );
}

const shopDomain  = shopUrl.replace(/^https?:\/\//, '').replace(/\/$/, '');
const shopifyBase = 'https://' + shopDomain + '/admin/api/' + apiVersion;

// Page strategy snippet from content_strategy for body generation
const pageStrategy = (contentStrategy.page_strategy || {});

console.log(
  `build-shopify-pages-navigation: project=${projectId}, shop=${shopDomain}, ` +
  `pages=${pages.length}, navigation=${navigation.length}`
);

return [{
  json: {
    project_id:       projectId,
    runtime_config:   runtimeConfig,
    store_blueprint:  storeBlueprint,
    content_strategy: contentStrategy,
    page_strategy:    pageStrategy,
    shop_url:         shopUrl,
    shop_domain:      shopDomain,
    api_version:      apiVersion,
    shopify_base:     shopifyBase,
    pages_count:      pages.length,
    navigation_count: navigation.length,
  },
}];

// build-shopify-pages-navigation — Build Upsert Plan
// Compares existing Shopify pages and menus against store_blueprint.
// Pages: REST API. Navigation: GraphQL Menu API (REST link_lists removed in 2025-04).
// Safety: no deletes, new pages published: false.

const items = $input.all();
const validated   = $node['Validate Pages/Nav Input'].json;
const blueprint   = validated.store_blueprint;
const shopifyBase = validated.shopify_base;

// Parse Merge Fetch Results — one item has pages (REST), other has menus (GraphQL)
let existingPages = [];
let existingMenus = [];

for (const item of items) {
  if (item.json.error) {
    console.log('Fetch node returned error (treating as empty):', JSON.stringify(item.json.error).slice(0, 200));
    continue;
  }
  if (item.json.pages !== undefined) existingPages = item.json.pages || [];
  // GraphQL menus response: { data: { menus: { edges: [{ node: {...} }] } } }
  if (item.json.data && item.json.data.menus) {
    existingMenus = (item.json.data.menus.edges || []).map(e => e.node);
  }
}

const pagesByHandle = {};
for (const p of existingPages) { if (p.handle) pagesByHandle[p.handle] = p; }
const menusByHandle = {};
for (const m of existingMenus) { if (m.handle) menusByHandle[m.handle] = m; }

console.log(`Build Upsert Plan: existing pages=${existingPages.length}, existing menus=${existingMenus.length}`);

// — GraphQL MenuItemType mapping —
function mapLinkType(linkType, target) {
  const t = (linkType || '').toLowerCase();
  if (t === 'frontpage' || t === 'home' || t === 'homepage') return { type: 'FRONTPAGE', url: '/' };
  if (t === 'page')       return { type: 'HTTP', url: '/pages/' + (target || '') };
  if (t === 'collection') return { type: 'HTTP', url: '/collections/' + (target || '') };
  if (t === 'product')    return { type: 'HTTP', url: '/products/' + (target || '') };
  if (t === 'blog')       return { type: 'HTTP', url: '/blogs/' + (target || '') };
  return { type: 'HTTP', url: target || '/' };
}

function generatePageHtml(page) {
  const safe = (s) => String(s || '').replace(/</g, '&lt;').replace(/>/g, '&gt;');
  const purpose = safe(page.purpose || '');
  const seo     = safe(page.seo_focus || '');
  let html = '';
  if (purpose) html += '<p>' + purpose + '</p>';
  if (seo && seo !== purpose) html += '<p>' + seo + '</p>';
  return html || '<p>Page content coming soon.</p>';
}

const actions = [];

// — Pages (REST) —
for (const page of (blueprint.pages || [])) {
  const handle   = page.handle || page.title.toLowerCase().replace(/[^a-z0-9]+/g, '-').replace(/^-|-$/g, '');
  const bodyHtml = page.body_html || generatePageHtml(page);
  const pageBody = { page: { title: page.title, handle, body_html: bodyHtml, author: 'store-os', published: false } };

  if (pagesByHandle[handle]) {
    const existingId = pagesByHandle[handle].id;
    actions.push({ resource: 'page', action: 'update', handle, shopify_id: existingId, url: shopifyBase + '/pages/' + existingId + '.json', body: pageBody, blueprint_title: page.title });
  } else {
    actions.push({ resource: 'page', action: 'create', handle, shopify_id: null, url: shopifyBase + '/pages.json', body: pageBody, blueprint_title: page.title });
  }
}

// — Navigation / Menus (GraphQL POST to /graphql.json) —
// Pre-compute blueprint page handles so the safety net can distinguish
// "will be created this run" from "genuine ghost that doesn't exist".
const blueprintPageHandles = new Set((blueprint.pages || []).map(function(p) { return p.handle; }));
const graphqlUrl = shopifyBase + '/graphql.json';

for (const menu of (blueprint.navigation || [])) {
  const handle = menu.menu_handle || menu.handle || (menu.title || '').toLowerCase().replace(/[^a-z0-9]+/g, '-').replace(/^-|-$/g, '');

  const gqlItems = (menu.items || []).map((item) => {
    const linkType = (item.link_type || '').toLowerCase();
    let mapped = mapLinkType(item.link_type, item.target);
    // Safety net: page nav targets must resolve to a real published Shopify page.
    // Blueprint pages are created with published:false in this same run — they won\'t 404 forever
    // but WILL 404 until manually published. Genuine ghost handles (not in blueprint AND not in
    // existingPages) are resolved to the nearest published page as a last resort.
    if (linkType === 'page') {
      const target = item.target || '';
      const existingPage = pagesByHandle[target];
      const isBlueprintPage = blueprintPageHandles.has(target);
      if (!existingPage && !isBlueprintPage) {
        const publishedPages = existingPages.filter(function(p) { return p.published_at; });
        if (publishedPages.length > 0) {
          const resolved = publishedPages[0];
          console.log('Nav safety-net: page target "' + target + '" is a ghost handle (not in store, not in blueprint) — resolved to published page "' + resolved.handle + '"');
          mapped = { type: 'HTTP', url: '/pages/' + resolved.handle };
        } else {
          console.log('Nav safety-net: page target "' + target + '" not found and no published pages exist — falling back to home');
          mapped = { type: 'FRONTPAGE', url: '/' };
        }
      }
    }
    return { title: item.label || item.title || item.target || '', type: mapped.type, url: mapped.url };
  });

  // Build inline GraphQL items string
  const itemsStr = gqlItems.map(i =>
    '{ title: ' + JSON.stringify(i.title) + ', type: ' + i.type + ', url: ' + JSON.stringify(i.url) + ' }'
  ).join(', ');

  if (menusByHandle[handle]) {
    const existingGid = menusByHandle[handle].id;
    const mutation = 'mutation { menuUpdate(id: ' + JSON.stringify(existingGid) + ', title: ' + JSON.stringify(menu.title) + ', items: [' + itemsStr + ']) { menu { id handle title items { id title type url } } userErrors { field message } } }';
    actions.push({
      resource: 'menu', action: 'create', _actual_action: 'update',
      handle, shopify_id: existingGid,
      url: graphqlUrl, body: { query: mutation },
      blueprint_title: menu.title,
    });
  } else {
    const mutation = 'mutation { menuCreate(title: ' + JSON.stringify(menu.title) + ', handle: ' + JSON.stringify(handle) + ', items: [' + itemsStr + ']) { menu { id handle title items { id title type url } } userErrors { field message } } }';
    actions.push({
      resource: 'menu', action: 'create', _actual_action: 'create',
      handle, shopify_id: null,
      url: graphqlUrl, body: { query: mutation },
      blueprint_title: menu.title,
    });
  }
}

console.log(`Build Upsert Plan: planned actions=${actions.length} (page creates=${actions.filter(a=>a.resource==='page'&&a.action==='create').length}, page updates=${actions.filter(a=>a.resource==='page'&&a.action==='update').length}, menu creates=${actions.filter(a=>a.resource==='menu'&&a._actual_action==='create').length}, menu updates=${actions.filter(a=>a.resource==='menu'&&a._actual_action==='update').length})`);

if (actions.length === 0) {
  return [{ json: { action: 'noop', resource: 'none', handle: null, url: null, body: null, blueprint_title: null, shopify_id: null } }];
}

return actions.map(a => ({ json: a }));

// build-shopify-pages-navigation — Compile Deployment Summary
// Aggregates HTTP results from Create Resource and Update Resource nodes.
// Handles REST responses (pages) and GraphQL responses (menus).

const results = $input.all();
const validated  = $node['Validate Pages/Nav Input'].json;
const projectId  = validated.project_id;
const shopDomain = validated.shop_domain;
const blueprint  = validated.store_blueprint;

let pagesCreated = 0, pagesUpdated = 0, navigationCreated = 0, navigationUpdated = 0;
const errors = [], warnings = [];

for (const item of results) {
  const d = item.json;
  if (d.action === 'noop') {
    warnings.push('No pages/navigation actions were planned');
    continue;
  }
  const statusCode = d.statusCode || 0;
  const body       = d.body || d;

  // GraphQL menu response (statusCode 200 but check userErrors)
  if (body.data && (body.data.menuCreate || body.data.menuUpdate)) {
    const result = body.data.menuCreate || body.data.menuUpdate;
    const userErrors = result.userErrors || [];
    if (userErrors.length > 0) {
      errors.push({
        resource: 'menu',
        handle: (result.menu && result.menu.handle) || 'unknown',
        status: 422,
        message: userErrors.map(e => e.message).join('; '),
      });
    } else if (result.menu) {
      if (body.data.menuCreate) navigationCreated++;
      else navigationUpdated++;
    }
    continue;
  }

  // REST page response
  if (statusCode >= 400 || d.error) {
    const errMsg = (body.errors ? JSON.stringify(body.errors) : null) || d.message || `HTTP ${statusCode} error`;
    errors.push({ resource: d._resource || 'unknown', handle: d._handle || 'unknown', status: statusCode, message: errMsg });
    continue;
  }
  const isPage = !!(body.page);
  if (statusCode === 201) { if (isPage) pagesCreated++; }
  else if (statusCode === 200) { if (isPage) pagesUpdated++; }
  else { warnings.push(`Unexpected HTTP ${statusCode} for ${isPage ? 'page' : 'resource'}`); }
}

const totalActioned = pagesCreated + pagesUpdated + navigationCreated + navigationUpdated;
const totalErrors   = errors.length;
const terminalStatus = totalErrors > 0 && totalActioned === 0 ? 'PHASE_7B2_FAILED' : totalErrors > 0 ? 'PHASE_7B2_PARTIAL' : 'PHASE_7B2_COMPLETE';

console.log(`Compile Deployment Summary: status=${terminalStatus}, pages_created=${pagesCreated}, pages_updated=${pagesUpdated}, navigation_created=${navigationCreated}, navigation_updated=${navigationUpdated}, errors=${totalErrors}`);

return [{ json: {
  status: terminalStatus, project_id: projectId, shop_url: shopDomain, completed_at: new Date().toISOString(),
  pages_created: pagesCreated, pages_updated: pagesUpdated, navigation_created: navigationCreated, navigation_updated: navigationUpdated,
  errors, warnings,
  blueprint_summary: { pages_in_blueprint: (blueprint.pages || []).length, navigation_in_blueprint: (blueprint.navigation || []).length },
  safety_notes: [
    'No Shopify resources were deleted — only create and update operations were performed',
    'All new pages were created with published: false — not visible until manually published',
    'Navigation menus deployed via Shopify GraphQL Menu API (REST link_lists deprecated)',
  ],
} }];
